import cadquery as cq

# Define parameters for the puzzle piece
base_size = 10.0          # Overall size of the square base
tab_width = 1.5           # Width of the tabs/notches
tab_depth = 1.0           # Depth of the tabs extending out/in
thickness = 2.0           # Thickness of the plate
num_tabs_per_side = 4     # Number of tabs per side (including corners)

# Calculate spacing between tabs
spacing = (base_size - 2 * tab_width) / (num_tabs_per_side - 1)

# Create the base square
base = cq.Workplane("XY").box(base_size, base_size, thickness)

# Function to add a tab or notch
def add_tab_notch(obj, direction, position):
    """
    Adds a tab or notch to the object.

    Args:
        obj: The current Workplane object
        direction: 'top', 'bottom', 'left', 'right'
        position: 'in' or 'out'

    Returns:
        Modified Workplane object
    """
    if direction == 'top':
        x_start = -(base_size/2) + spacing/2
        y_start = base_size/2 - tab_depth
        width = tab_width
        height = tab_depth

        if position == 'out':
            return obj.faces(">Z").workplane().rect(width, height).extrude(tab_depth)
        else:
            return obj.faces(">Z").workplane().rect(width, height).cutThruAll()

    elif direction == 'bottom':
        x_start = -(base_size/2) + spacing/2
        y_start = -base_size/2 + tab_depth
        width = tab_width
        height = tab_depth

        if position == 'out':
            return obj.faces("<Z").workplane().rect(width, height).extrude(-tab_depth)
        else:
            return obj.faces("<Z").workplane().rect(width, height).cutThruAll()

    elif direction == 'left':
        x_start = -base_size/2 + tab_depth
        y_start = -(base_size/2) + spacing/2
        width = tab_depth
        height = tab_width

        if position == 'out':
            return obj.faces("<X").workplane().rect(width, height).extrude(tab_depth)
        else:
            return obj.faces("<X").workplane().rect(width, height).cutThruAll()

    elif direction == 'right':
        x_start = base_size/2 - tab_depth
        y_start = -(base_size/2) + spacing/2
        width = tab_depth
        height = tab_width

        if position == 'out':
            return obj.faces(">X").workplane().rect(width, height).extrude(-tab_depth)
        else:
            return obj.faces(">X").workplane().rect(width, height).cutThruAll()

# Build the puzzle piece by adding tabs and notches
result = base

# Add tabs and notches to each side
for i in range(num_tabs_per_side):
    # Top side
    result = add_tab_notch(result, 'top', 'out' if i % 2 == 0 else 'in')
    # Bottom side
    result = add_tab_notch(result, 'bottom', 'out' if i % 2 == 0 else 'in')
    # Left side
    result = add_tab_notch(result, 'left', 'out' if i % 2 == 0 else 'in')
    # Right side
    result = add_tab_notch(result, 'right', 'out' if i % 2 == 0 else 'in')

# Final result
result = result
